import numpy as np

def binary_preference_loss(r_pos, r_neg):
    return -np.log(1.0 / (1.0 + np.exp(-(r_pos - r_neg))))

def run_practice():
    loss = binary_preference_loss(1.0, 1.0)
    assert np.allclose(loss, 0.693147)
    print('[PASS] Preference loss calculation matches predictions.')

if __name__ == '__main__':
    run_practice()
